from functools import wraps
import time

app = Flask(__name__)
app.secret_key = 'your_secret_key'
redis_client = Redis(host='localhost', port=6379, db=0)

def cache(expiration=60):
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            cache_key = f"{f.__name__}:{args}:{kwargs}"
            cached_result = redis_client.get(cache_key)
            if cached_result:
                return jsonify({'cached': True, 'result': cached_result.decode('utf-8')})
            result = f(*args, **kwargs)
            redis_client.setex(cache_key, expiration, result)
            return jsonify({'cached': False, 'result': result})
        return decorated_function
    return decorator

@app.route('/set_session/<username>')
def set_session(username):
    session['username'] = username
    redis_client.set(f"session:{session.sid}", username)
    return f"Session set for {username}"

@app.route('/get_session')
def get_session():
    username = redis_client.get(f"session:{session.sid}")
    if username:
        return f"Session retrieved for {username.decode('utf-8')}"
    return "No session found"

@cache(expiration=120)
def expensive_db_query(param):
    time.sleep(5)  # Simulate a long-running query
